sparql_query:
PREFIX goo:    <https://ucf-henat.github.io/GeoOutageOnto/#>
PREFIX gokg:   <http://example.org/resource#>
PREFIX xsd:    <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf:    <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs:   <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?ntl ?date ?locator
WHERE {
  ?ntl a goo:NTLImage ;
       goo:acquisitionDateTime ?date ;
       goo:representsCounty gokg:OrangeCountyFL ;
       goo:sourceDownloadUrl ?locator .
  FILTER (?date >= "2025-01-01T00:00:00Z"^^xsd:dateTime && ?date < "2026-01-01T00:00:00Z"^^xsd:dateTime)
}
ORDER BY ?date
LIMIT 10
